mapper.select:
/* com.shop.mapper.code.selectPartnerCodeListPaging */ SELECT ( COUNT(1) OVER() ) AS totalRowCount , ROW_NUMBER() OVER(ORDER BY TC.ID ASC) AS no , TC.ID AS id , TC.CODE_UPPER AS codeUpper , COALESCE((SELECT X.CODE_NM FROM TB_PARTNER_CODE X WHERE X.CODE_CD = TC.CODE_UPPER LIMIT 1), TC.CODE_UPPER) AS codeUpperNm , TC.CODE_CD AS codeCd , TC.CODE_NM AS codeNm , TC.DEF_CODE_VAL AS defCodeVal , (SELECT COUNT(*) FROM TB_PARTNER_CODE X WHERE X.CODE_UPPER = TC.CODE_CD) AS lowerCodeCnt , CASE WHEN COALESCE(TC.CODE_DESC, '') = '' THEN '-' ELSE TC.CODE_DESC END AS codeDesc , CASE WHEN COALESCE(TC.CODE_ETC, '') = '' THEN '-' ELSE TC.CODE_ETC END AS codeEtc , TC.CODE_ORDER AS codeOrder , TC.CRE_TM AS creTm , TC.CRE_USER AS creUser , TC.UPD_TM AS updTm , TC.UPD_USER AS updUser , TC.DEL_YN AS deleteYn , TC.CODE_ETC1 , TC.CODE_ETC2 , TC.CODE_ETC3 FROM TB_PARTNER_CODE TC WHERE TC.PARTNER_ID = #{partnerId}
AND TC.CODE_UPPER = #{filter.codeUpper}
AND TC.CODE_CD LIKE CONCAT('%', #{filter.codeCd}, '%')
AND TC.CODE_NM LIKE CONCAT('%', #{filter.codeNm}, '%')
ORDER BY TC.ID DESC OFFSET (#{curPage}-1) * #{pageRowCount} ROWS FETCH NEXT #{pageRowCount} ROWS ONLY

/* com.shop.mapper.code.selectPartnerCodeByUk */
SELECT 
FROM TB_PARTNER_CODE
WHERE CODE_UPPER = #{codeUpper}
AND CODE_CD = #{codeCd}
AND PARTNER_ID = #{partnerId}
AND DEL_YN = 'N'

/* com.shop.mapper.code.getDupCodeInfo */
SELECT CONCAT(${column},' ',COUNT(*),' 건')
FROM TB_PARTNER_CODE
WHERE CODE_UPPER = #{codeUpper}
  AND PARTNER_ID = #{partnerId}
  AND DEL_YN = 'N'
GROUP BY ${column}
HAVING COUNT(*) > 1

/* com.shop.mapper.code.selectLowerCodeByCodeUpperForPartnerCodeMng */ SELECT
, ROW_NUMBER() OVER(ORDER BY TC.CODE_ORDER ASC) AS no , COALESCE((SELECT USER_NM FROM TB_USER X WHERE TC.UPD_USER = X.LOGIN_ID), TC.UPD_USER) AS updNm , COALESCE((SELECT USER_NM FROM TB_USER X WHERE TC.CRE_USER = X.LOGIN_ID), TC.CRE_USER) AS creNm FROM TB_PARTNER_CODE TC WHERE 1 = 1 AND TC.DEL_YN = 'N' AND TC.CODE_UPPER = #{codeUpper} AND TC.PARTNER_ID = #{partnerId}
AND TC.CODE_NM LIKE CONCAT('%', #{codeNm}, '%')
AND TC.CODE_CD = #{codeCd}
AND ( TC.CODE_CD LIKE CONCAT('%', #{searchKeyword}, '%') OR TC.CODE_NM LIKE CONCAT('%', #{searchKeyword}, '%') OR TC.CODE_DESC LIKE CONCAT('%', #{searchKeyword}, '%') OR TC.CODE_ETC LIKE CONCAT('%', #{searchKeyword}, '%') )
ORDER BY TC.CODE_NM ASC
ORDER BY TC.CODE_ORDER ASC

