/* com.shop.mapper.code.insertPartnerCode */
INSERT INTO TB_PARTNER_CODE
(
CODE_UPPER
, CODE_CD
, CODE_NM
, PARTNER_ID

    , CODE_DESC


    , DEF_CODE_VAL


    , CODE_ETC


    , CODE_ETC1


    , CODE_ETC2


    , CODE_ETC3

, CODE_ORDER
, CRE_USER
, UPD_USER

    , DEL_YN

)
VALUES
(
#{codeUpper}
, #{codeCd}
, #{codeNm}
, #{partnerId}

    , #{codeDesc}


    , #{defCodeVal}


    , #{codeEtc}


    , #{codeEtc1}


    , #{codeEtc2}


    , #{codeEtc3}



        , #{codeOrder}


        , (SELECT COALESCE(MAX(CODE_ORDER), 0) + 1
        FROM TB_PARTNER_CODE
        WHERE PARTNER_ID = #{partnerId}
        AND CODE_UPPER = #{codeUpper})


, #{creUser}
, #{creUser}

    , #{delYn}

)

mapper.update:
/* com.shop.mapper.code.updatePartnerCode */
UPDATE TB_PARTNER_CODE
SET UPD_TM   = NOW()
, UPD_USER = #{updUser}

    , CODE_UPPER = #{codeUpper}


    , CODE_CD = #{codeCd}


    , CODE_NM = #{codeNm}


    , CODE_DESC = #{codeDesc}


    , DEF_CODE_VAL = #{defCodeVal}


    , CODE_ETC = #{codeEtc}


    , CODE_ETC1 = #{codeEtc1}


    , CODE_ETC2 = #{codeEtc2}


    , CODE_ETC3 = #{codeEtc3}


    , CODE_ORDER = #{codeOrder}


    , DEL_YN = #{delYn}

WHERE ID = #{id}

/* com.shop.mapper.code.deletePartnerCode */
UPDATE TB_PARTNER_CODE
SET DEL_YN = 'Y'
, UPD_USER = #{updUser}
, UPD_TM = NOW()
WHERE ID = #{id}

